import AVFoundation
import SwiftUI

@Observable
class DJMixerViewModel {
    var crossfadeValue: Float = 0.5
    var deckAVolume: Float = 1.0
    var deckBVolume: Float = 1.0
    var waveformA: [Float] = []
    var waveformB: [Float] = []
    var errorMessage: String?

    private let engine = AVAudioEngine()
    private let playerA = AVAudioPlayerNode()
    private let playerB = AVAudioPlayerNode()
    private let mixerA = AVAudioMixerNode()
    private let mixerB = AVAudioMixerNode()
    private var fileA: AVAudioFile?
    private var fileB: AVAudioFile?

    init() {
        setupEngine()
    }

    private func setupEngine() {
        engine.attach(playerA)
        engine.attach(playerB)
        engine.attach(mixerA)
        engine.attach(mixerB)

        engine.connect(playerA, to: mixerA, format: nil)
        engine.connect(playerB, to: mixerB, format: nil)
        engine.connect(mixerA, to: engine.mainMixerNode, format: nil)
        engine.connect(mixerB, to: engine.mainMixerNode, format: nil)

        do {
            let session = AVAudioSession.sharedInstance()
            try session.setCategory(.playback, mode: .default)
            try session.setActive(true)
            engine.prepare()
            try engine.start()
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    func loadDeckA(url: URL) {
        do {
            let file = try AVAudioFile(forReading: url)
            fileA = file
            playerA.stop()
            playerA.scheduleFile(file, at: nil)
            waveformA = loadWaveformData(from: url)
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    func loadDeckB(url: URL) {
        do {
            let file = try AVAudioFile(forReading: url)
            fileB = file
            playerB.stop()
            playerB.scheduleFile(file, at: nil)
            waveformB = loadWaveformData(from: url)
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    func playDeckA() { playerA.play() }
    func stopDeckA() { playerA.stop() }
    func playDeckB() { playerB.play() }
    func stopDeckB() { playerB.stop() }

    func applyCrossfade() {
        mixerA.outputVolume = 1.0 - crossfadeValue
        mixerB.outputVolume = crossfadeValue
    }

    private func loadWaveformData(from url: URL, numberOfPoints: Int = 200) -> [Float] {
        guard let file = try? AVAudioFile(forReading: url) else { return [] }
        let format = file.processingFormat
        let frameCount = AVAudioFrameCount(file.length)
        guard let buffer = AVAudioPCMBuffer(pcmFormat: format, frameCapacity: frameCount) else { return [] }
        guard (try? file.read(into: buffer)) != nil else { return [] }
        guard let channelData = buffer.floatChannelData?[0] else { return [] }
        let samples = Array(UnsafeBufferPointer(start: channelData, count: Int(buffer.frameLength)))
        guard !samples.isEmpty else { return [] }
        let chunkSize = max(1, samples.count / numberOfPoints)
        return stride(from: 0, to: samples.count, by: chunkSize).map { i in
            let chunk = samples[i..<min(i + chunkSize, samples.count)]
            return chunk.map { abs($0) }.max() ?? 0
        }
    }
}

